    58→  void recordValue(uint64_t value) override;
    59→
    60→  // Stats::Metric
    61→  SymbolTable& symbolTable() final { return symbol_table_; }
    62→  bool used() const override { return used_; }
    63→  bool hidden() const override { return false; }
    64→
    65→private:
    66→  Histogram::Unit unit_;
    67→  uint64_t otherHistogramIndex() const { return 1 - current_active_; }
    68→  uint64_t current_active_{0};
    69→  histogram_t* histograms_[2];
    70→  std::atomic<bool> used_;
    71→  std::thread::id created_thread_id_;
